String _docCard(JsonMap project, JsonMap doc) {
  final href = _repoBlob(project, doc['url'] as String);
  return '<a href="${_html(href)}"><strong>${_html(doc['title'] as String)}</strong><span>${_html(doc['description'] as String)}</span></a>';
}

String _recipeCard(JsonMap recipe) {
  return '''
<article>
  <span>${_html(recipe['surface'] as String)}</span>
  <h3>${_html(recipe['name'] as String)}</h3>
  <p>${_html(recipe['apps'] as String)}</p>
  <code>${_html(recipe['apis'] as String)}</code>
</article>
''';
}

/// Embeds the FAQ as schema.org `FAQPage` JSON-LD so search engines can render
/// answer-rich results. Sourced from the manifest `faq`, so it never drifts
/// from `faq-ai.txt` or the on-page FAQ.
String _faqJsonLd(JsonMap manifest) {
  final faq = _maps(manifest['faq']);
  return jsonEncode(<String, Object?>{
    '@context': 'https://schema.org',
    '@type': 'FAQPage',
    'mainEntity': [
      for (final item in faq)
        {
          '@type': 'Question',
          'name': item['question'],
          'acceptedAnswer': {'@type': 'Answer', 'text': item['answer']},
        },
    ],
  });
}

/// Inline, dependency-free SVG icons. Inline keeps the site self-contained (no
/// icon CDN) and recolourable via `currentColor`. Icons are decorative —
/// every use is paired with a visible text label, so they are `aria-hidden`.
String _icon(String name) {
  const open =
      '<svg class="i" viewBox="0 0 24 24" aria-hidden="true" focusable="false"';
  String stroke(String path) =>
      '$open fill="none" stroke="currentColor" stroke-width="2" '
      'stroke-linecap="round" stroke-linejoin="round"><path d="$path"/></svg>';
  String fill(String path) =>
      '$open fill="currentColor"><path d="$path"/></svg>';
  switch (name) {
    case 'github':
      return fill(
        'M12 .5C5.73.5.5 5.73.5 12c0 5.08 3.29 9.39 7.86 10.91.58.11.79-.25.79'
        '-.56 0-.27-.01-1.01-.02-1.98-3.2.7-3.88-1.54-3.88-1.54-.52-1.33-1.28'
        '-1.69-1.28-1.69-1.05-.72.08-.7.08-.7 1.16.08 1.77 1.19 1.77 1.19 1.03 '
        '1.77 2.7 1.26 3.36.96.1-.75.4-1.26.73-1.55-2.55-.29-5.24-1.28-5.24-5.69 '
        '0-1.26.45-2.29 1.19-3.1-.12-.29-.52-1.46.11-3.05 0 0 .97-.31 3.18 1.18a'
        '11.1 11.1 0 0 1 5.79 0c2.2-1.49 3.17-1.18 3.17-1.18.63 1.59.23 2.76.11 '
        '3.05.74.81 1.19 1.84 1.19 3.1 0 4.42-2.69 5.39-5.25 5.68.41.36.78 1.06.78 '
        '2.14 0 1.55-.01 2.8-.01 3.18 0 .31.21.68.8.56A11.52 11.52 0 0 0 23.5 12C'
        '23.5 5.73 18.27.5 12 .5Z',
      );
    case 'pub':
      return stroke(
        'M12 2.5 3.5 7v10L12 21.5 20.5 17V7L12 2.5Z M3.5 7 12 11.5 20.5 7 M12 11.5V21.5',
      );
    case 'book':
      return stroke(
        'M12 6C10.5 4.8 8.7 4 6.5 4H3v13h4c1.9 0 3.6.6 5 1.7M12 6c1.5-1.2 3.3-2 '
        '5.5-2H21v13h-4c-1.9 0-3.6.6-5 1.7M12 6v12.7',
      );
    case 'blocks':
      return stroke(
        'M4 4h6v6H4V4Z M14 4h6v6h-6V4Z M4 14h6v6H4v-6Z M14 14h6v6h-6v-6Z',
      );
    case 'terminal':
      return stroke(
        'M4 5h16a1 1 0 0 1 1 1v12a1 1 0 0 1-1 1H4a1 1 0 0 1-1-1V6a1 1 0 0 1 1-1Z M7 9.5l3 2.5-3 2.5 M13 15h4',
      );
    case 'shield':
      return stroke(
        'M12 3 5 6v5c0 4 2.9 7 7 8 4.1-1 7-4 7-8V6l-7-3Z M9.5 11.5l1.8 1.8 3.4-3.6',
      );
    case 'pen':
      return stroke('M16.5 4.5 19.5 7.5 9 18l-4 1 1-4 10.5-10.5Z M14 7l3 3');
    case 'layers':
      return stroke(
        'M12 3 2.5 8 12 13l9.5-5L12 3Z M2.5 12 12 17l9.5-5 M2.5 16 12 21l9.5-5',
      );
    case 'bolt':
      return fill('M13 2 4 13h6l-1 9 9-13h-6l1-7Z');
    case 'check':
      return stroke('M5 12.5 10 17.5 19.5 6.5');
    default:
      return '';
  }
}

String _siteNotFound(JsonMap manifest) {
  final project = _map(manifest['project']);
  return '''
<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>Not found - ${_html(project['short_title'] as String)}</title>
  <link rel="stylesheet" href="styles.css">
</head>
<body class="not-found">
  <main>
    <p class="eyebrow">404</p>
    <h1>This pqforge page is not here.</h1>
    <p>Start from the generated visibility homepage.</p>
    <a class="button primary" href="index.html">Open pqforge</a>
  </main>
</body>
</html>
''';
}

String _siteCss() {
  return r'''
:root {
  color-scheme: dark;
  --ink: #f7fbff;
  --muted: #9fb1c7;
  --panel: rgba(9, 17, 29, .78);
  --panel-strong: rgba(15, 29, 46, .94);
  --line: rgba(174, 209, 255, .18);
  --cyan: #52e0d5;
  --gold: #f5c35b;
  --rose: #ff6f91;
  --green: #84e68b;
  --bg: #07111d;
  font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
}

* { box-sizing: border-box; }

html { scroll-behavior: smooth; }

body {
  margin: 0;
  background:
    linear-gradient(120deg, rgba(82, 224, 213, .16), transparent 30%),
    linear-gradient(200deg, rgba(245, 195, 91, .12), transparent 35%),
    var(--bg);
  color: var(--ink);
}

a { color: inherit; text-decoration: none; }

.topbar {
  position: sticky;
  top: 0;
  z-index: 10;
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 24px;
  padding: 14px clamp(20px, 4vw, 56px);
  background: rgba(7, 17, 29, .82);
  border-bottom: 1px solid var(--line);
  backdrop-filter: blur(18px);
}

.brand { display: inline-flex; align-items: center; gap: 10px; font-weight: 800; }
.brand-mark {
  display: grid;
  place-items: center;
  width: 36px;
  height: 36px;
  border-radius: 8px;
  background: linear-gradient(135deg, var(--cyan), var(--gold));
  color: #06111d;
  font-size: 13px;
}

nav { display: flex; flex-wrap: wrap; gap: 18px; color: var(--muted); font-size: 14px; }
nav a:hover { color: var(--ink); }

.hero {
  min-height: min(720px, 76vh);
  display: grid;
  grid-template-columns: minmax(0, .95fr) minmax(320px, 560px);
  gap: clamp(28px, 5vw, 72px);
  align-items: center;
  padding: clamp(36px, 5vw, 68px) clamp(20px, 5vw, 72px) 34px;
}

.hero-copy { max-width: 760px; }
.eyebrow {
  margin: 0 0 12px;
  color: var(--cyan);
  text-transform: uppercase;
  font-size: 12px;
  font-weight: 800;
  letter-spacing: .12em;
}

h1, h2, h3 { margin: 0; letter-spacing: 0; line-height: 1.04; }
h1 { font-size: clamp(42px, 4.2vw, 64px); max-width: 760px; }
h2 { font-size: clamp(30px, 4vw, 54px); }
h3 { font-size: 20px; }

.lede {
  max-width: 760px;
  margin: 18px 0 0;
  color: var(--muted);
  font-size: clamp(17px, 1.6vw, 19px);
  line-height: 1.65;
}

.hero-actions { display: flex; flex-wrap: wrap; gap: 12px; margin-top: 24px; }
.button {
  display: inline-flex;
  min-height: 44px;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 0 18px;
  border-radius: 8px;
  font-weight: 800;
  transition: transform .15s ease, filter .15s ease, border-color .15s ease;
}
.button:hover { transform: translateY(-1px); }
.primary { background: var(--cyan); color: #06111d; }
.primary:hover { filter: brightness(1.06); }
.secondary { border: 1px solid var(--line); color: var(--ink); background: rgba(255,255,255,.04); }
.secondary:hover { border-color: var(--cyan); }
.ghost { border: 1px solid var(--line); color: var(--ink); background: transparent; }
.ghost:hover { border-color: var(--cyan); color: var(--cyan); }

.hero-visual {
  margin: 0;
  min-height: 360px;
  border: 1px solid var(--line);
  border-radius: 8px;
  overflow: hidden;
  background: rgba(255,255,255,.04);
  box-shadow: 0 30px 90px rgba(0,0,0,.35);
}
.hero-visual img { width: 100%; height: 100%; display: block; object-fit: cover; }

.signal-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 1px;
  margin: 0 clamp(20px, 5vw, 72px);
  border: 1px solid var(--line);
  background: var(--line);
}
.signal-grid div { padding: 24px; background: var(--panel); }
.signal-grid strong { display: block; font-size: 34px; color: var(--gold); }
.signal-grid span { color: var(--muted); }

.section { padding: clamp(58px, 8vw, 110px) clamp(20px, 5vw, 72px); }
.section-heading { max-width: 760px; margin-bottom: 28px; }
.section-heading h2 + p { color: var(--muted); }

.recipes, .use-cases, .doc-grid, .profile-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 14px;
}

.recipes article, .use-cases div, .doc-grid a, .profile-grid div, details {
  min-height: 100%;
  padding: 22px;
  border: 1px solid var(--line);
  border-radius: 8px;
  background: var(--panel);
}
.recipes article span, .profile-grid span, .doc-grid span {
  display: block;
  color: var(--muted);
  margin-top: 10px;
  line-height: 1.55;
}
.recipes p, .use-cases p, .boundary p, details p { color: var(--muted); line-height: 1.6; }
code {
  display: block;
  margin-top: 14px;
  color: var(--green);
  white-space: normal;
  overflow-wrap: anywhere;
}

.split {
  display: grid;
  grid-template-columns: minmax(0, .75fr) minmax(320px, 1.25fr);
  gap: 30px;
  align-items: start;
  background: rgba(82, 224, 213, .06);
}
.terminal {
  margin: 0;
  padding: 22px;
  border-radius: 8px;
  border: 1px solid var(--line);
  background: #050b12;
  color: #d5f7ef;
  overflow-x: auto;
  line-height: 1.7;
}
.terminal code { margin: 0; white-space: pre; }

.boundary {
  display: grid;
  grid-template-columns: .8fr 1.2fr;
  gap: 24px;
  background: rgba(245, 195, 91, .06);
}
.boundary ul {
  margin: 0;
  padding: 0;
  display: grid;
  gap: 10px;
  list-style: none;
}
.boundary li {
  padding: 14px 16px;
  border: 1px solid var(--line);
  border-radius: 8px;
  background: var(--panel);
}

details { margin-bottom: 10px; }
summary { cursor: pointer; font-weight: 800; }

footer {
  display: flex;
  flex-wrap: wrap;
  gap: 18px;
  justify-content: space-between;
  padding: 28px clamp(20px, 5vw, 72px);
  color: var(--muted);
  border-top: 1px solid var(--line);
}

.not-found main { max-width: 720px; margin: 18vh auto; padding: 24px; }

/* Inline icons */
.i { width: 1.05em; height: 1.05em; display: inline-block; vertical-align: -.16em; flex: none; }

/* Topbar external links */
.topbar-right { display: flex; align-items: center; gap: clamp(14px, 2.4vw, 28px); }
.topbar-links { display: flex; align-items: center; gap: 8px; }
.ext {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  padding: 7px 12px;
  border: 1px solid var(--line);
  border-radius: 8px;
  background: rgba(255, 255, 255, .03);
  color: var(--ink);
  font-size: 13px;
  font-weight: 700;
  transition: border-color .15s ease, color .15s ease, background .15s ease;
}
.ext:hover { border-color: var(--cyan); color: var(--cyan); background: rgba(82, 224, 213, .08); }

/* Hero credibility badges */
.hero-badges { list-style: none; display: flex; flex-wrap: wrap; gap: 10px; margin: 24px 0 0; padding: 0; }
.hero-badges li {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  padding: 7px 13px;
  border: 1px solid var(--line);
  border-radius: 999px;
  background: var(--panel);
  color: var(--muted);
  font-size: 13px;
  font-weight: 600;
}
.hero-badges .i { color: var(--green); }

/* Signal grid icons */
.signal-grid div { display: flex; flex-direction: column; gap: 6px; }
.signal-grid .i { width: 24px; height: 24px; color: var(--cyan); }

/* Card hover polish */
.recipes article, .doc-grid a, .profile-grid div { transition: border-color .15s ease, transform .15s ease; }
.recipes article:hover, .doc-grid a:hover, .profile-grid div:hover { border-color: var(--cyan); transform: translateY(-2px); }

/* Footer links with icons */
footer a { display: inline-flex; align-items: center; gap: 7px; transition: color .15s ease; }
footer a:hover { color: var(--cyan); }

/* Sticky-header offset for in-page anchors */
.section, #top { scroll-margin-top: 84px; }

@media (max-width: 900px) {
  .hero, .split, .boundary { grid-template-columns: 1fr; }
  .recipes, .use-cases, .doc-grid, .profile-grid, .signal-grid { grid-template-columns: 1fr; }
  .topbar { align-items: flex-start; flex-direction: column; }
  .topbar-right { flex-direction: column; align-items: flex-start; gap: 12px; width: 100%; }
  .topbar-links { flex-wrap: wrap; }
  h1 { font-size: 42px; }
}
''';
}

String _faviconSvg() {
  return r'''
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64">
  <rect width="64" height="64" rx="12" fill="#07111d"/>
  <path d="M14 18h21c8 0 13 5 13 12s-5 12-13 12H26v10H14V18Zm12 10v14h8c4 0 6-3 6-7s-2-7-6-7h-8Z" fill="#52e0d5"/>
  <path d="M43 44l8 8" stroke="#f5c35b" stroke-width="6" stroke-linecap="round"/>
