String _sitemap(JsonMap manifest) {
  final project = _map(manifest['project']);
  return '''
<?xml version="1.0" encoding="UTF-8"?>
<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">
  <url><loc>${project['canonical_url']}</loc></url>
  <url><loc>${project['canonical_url']}llms.txt</loc></url>
  <url><loc>${project['canonical_url']}llms-full.txt</loc></url>
  <url><loc>${project['canonical_url']}identity.json</loc></url>
</urlset>
''';
}

String _mdComment() => '<!-- $_generatedNotice -->';

String _repoBlob(JsonMap project, String path) {
  return '${project['repository']}/blob/${project['repository_branch']}/$path';
}

JsonMap _map(Object? value) => Map<String, dynamic>.from(value as Map);

List<JsonMap> _maps(Object? value) =>
    (value as List).map((item) => _map(item)).toList();

List<String> _strings(Object? value) =>
    (value as List).map((item) => item.toString()).toList();

String _html(String value) {
  return value
      .replaceAll('&', '&amp;')
      .replaceAll('<', '&lt;')
      .replaceAll('>', '&gt;')
      .replaceAll('"', '&quot;');
}
